const allResults = $input.all().flatMap((item) => item.json?.data?.results ?? []);

const CHECKS = {
  'Beschreibung fehlt': (d) => !d.notes?.trim(),
  'Autor fehlt': (d) => !d.author?.trim(),
  'Autor-E-Mail fehlt': (d) => !d.author_email?.trim(),
  'Lizenz fehlt': (d) => !d.license_id?.trim(),
  'Titel fehlt': (d) => !d.title?.trim(),
  'URL fehlt': (d) => !d.url?.trim(),
  'Organisation fehlt': (d) => !d.organization,
};

const report = allResults
  .map((d) => ({
    dataset_id: d.id,
    dataset_name: d.name ?? '(unbekannt)',
    issues: Object.entries(CHECKS)
      .filter(([, check]) => check(d))
      .map(([label]) => label),
  }))
  .filter((r) => r.issues.length > 0);

return [
  {
    json: {
      totalScanned: allResults.length,
      totalInvalid: report.length,
      datasets: report,
      generatedAt: new Date().toISOString(),
    },
  },
];
